proof fn phi_4_endpoints_contain_false_for_absent(endpoints: Vec<EndPoint>, ep: EndPoint)
    requires
        endpoints@.len() > 0,
        forall|i: int| 0 <= i < endpoints@.len() ==> endpoints@[i]@.id != ep@.id,
    ensures
        !abstractify_end_points(endpoints).contains(ep@),
